const crypto = global.get('crypto');

var subjectId = global.get("subjectId_2");
var token = global.get("token_2");
var appid = global.get("appid_2");
var appkey = global.get("appkey_2");
var userid = global.get("userid_2");
var aqara_url = global.get("aqara_url_2");
var area = global.get("area_2");

// 👉 query params (ordinati!)
const paramsObj = {
    options: "",
    subjectId: subjectId,
    viewId: "detail"
};

// 👉 costruzione stile urlencode (IMPORTANTISSIMO)
const queryString = Object.entries(paramsObj)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
    .join('&');

// Nonce
const uuid = crypto.randomUUID();
const nonce = crypto.createHash('md5').update(uuid).digest('hex');

// Time
const time = Date.now().toString();

// 👉 SIGN (con query string)
const signString = `Appid=${appid}&Nonce=${nonce}&Time=${time}&Token=${token}&${queryString}&${appkey}`;
const sign = crypto.createHash('md5').update(signString).digest('hex');

// Headers completi
msg.headers = {
    "Appid": appid,
    "Token": token,
    "Userid": userid,
    "Nonce": nonce,
    "Time": time,
    "Sign": sign,
    "Area": area
};

// URL finale
msg.url = `https://${aqara_url}/app/v1.0/lumi/app/view/data/query?${queryString}`;
msg.method = "GET";

return msg;

